python
class PRR:
    def __init__(self, pattern_type):
        self.pattern_type = pattern_type

    def detect(self, molecule):
        return molecule == self.pattern_type

class Caspase1:
    def activate(self):
        print("Caspase-1 activated")
        return True

class ASC:
    def recruit_caspase(self):
        print("ASC recruits pro-caspase-1")
        return Caspase1()

def inflammasome_simulation(lps_present):
    prr = PRR('LPS')
    if prr.detect('LPS') and lps_present:
        asc = ASC()
        caspase1 = asc.recruit_caspase()
        caspase1.activate()
        print("Inflammasome assembled and inflammatory response initiated.")
    else:
        print("No inflammasome activation.")

# Example usage:
inflammasome_simulation(lps_present=True)
